function LxMgrCenter:AddManager(name, manager, needInit)
    if name == nil then
        LogError('gLxMgrCenter AddManager Error name is nil...')
        return
    end
    if manager == nil then
        LogError('gLxMgrCenter AddManager Error manager is nil...')
        return
    end

    table.insert(self._names, name)
    self._managers[name] = manager
    if needInit then
        manager:Initialize()
    else
        table.insert(self._notInitNames, name)
    end
end

function LxMgrCenter:Dispose()
    local managers = self._managers
    local names = self._names
    if managers then
        for k=#names,1,-1 do
            local name = names[k]
            local manager = managers[name]
            manager:Dispose()
            managers[name] = nil
        end
    end
    self._names = nil
    self._managers = nil
    self._notInitNames = nil
    table.dispose(MgrCenter)
    table.dispose(ModuleCenter)
    table.dispose(self)
end

function LxMgrCenter:InitAfterLogin()
    local managers = self._managers
    for k, v in ipairs(self._notInitNames) do
        local manager = managers[v]
        if manager then
            manager:Initialize()
        end
    end

    for k, v in ipairs(self._notInitNames) do
        local manager = managers[v]
        if manager then
            manager:DoAfterInitialize()
        end
    end
    self._notInitNames = {}
end

return LxMgrCenter